let mode = "menu";
let selectedQuestions = [];
let currentQ = 0;
let userAnswers = {};
let timerInterval;
let seconds = 0;
let examTime = 60 * 60;
let flaggedQuestions = new Set();
let examModeActive = false;
let userNotes = JSON.parse(localStorage.getItem('droneNotes')) || {};
let finishModalShown = false;

document.addEventListener("DOMContentLoaded", () => {
    document.getElementById("landingScreen").style.display = "flex";
    document.getElementById("landingNavbar").style.display = "flex";
    updateGlobalStats();
    loadUserProfile();
});

function goMenu() {
    clearInterval(timerInterval);
    document.querySelectorAll('body > div').forEach(el => {
        if(el.id !== 'topNavbar') el.style.display = 'none';
    });
    document.getElementById('landingNavbar').style.display = 'none';
    document.getElementById('topNavbar').style.display = 'flex';
    document.getElementById('menu').style.display = 'flex';
    document.body.style.overflow = "hidden";
}

function openLoginModal() {
    document.getElementById('loginModal').style.display = 'flex';
}

function closeLoginModal() {
    document.getElementById('loginModal').style.display = 'none';
}

function doLogin() {
    const email = document.getElementById('loginEmail').value;
    if(email) {
        localStorage.setItem('droneUser', email);
        document.getElementById('candidateNameMock').innerText = "Χρήστης: " + email;
    }
    closeLoginModal();
    goMenu();
}

function logoutMock() {
    localStorage.removeItem('droneUser');
    location.reload();
}

function openSettings() {
    document.getElementById('settingsScreen').style.display = 'flex';
}

function saveSettings() {
    const un = document.getElementById('setUsername').value;
    document.getElementById('candidateNameMock').innerText = "Χρήστης: " + un;
    alert("Οι ρυθμίσεις αποθηκεύτηκαν επιτυχώς!");
    goMenu();
}

function resetAllData() {
    if(confirm("Είστε σίγουροι; Όλα τα στατιστικά, ιστορικό και σημειώσεις θα διαγραφούν!")) {
        localStorage.removeItem('examHistory');
        localStorage.removeItem('studyStats');
        localStorage.removeItem('droneNotes');
        userNotes = {};
        alert("Τα δεδομένα διαγράφηκαν.");
        location.reload();
    }
}

function toggleTheme() {
    document.body.classList.toggle('dark');
    const isDark = document.body.classList.contains('dark');
    localStorage.setItem('theme', isDark ? 'dark' : 'light');
}

if(localStorage.getItem('theme') === 'dark') {
    document.body.classList.add('dark');
}

function openTheory() {
    document.getElementById('menu').style.display = 'none';
    document.getElementById('theoryScreen').style.display = 'flex';
    
    const sidebar = document.getElementById('theorySidebar');
    sidebar.innerHTML = '';
    
    easaTheoryData.forEach((mod, index) => {
        const btn = document.createElement('button');
        btn.className = 'theory-module-btn';
        btn.innerText = mod.title;
        btn.onclick = () => loadTheoryContent(index, btn);
        sidebar.appendChild(btn);
    });
}

function loadTheoryContent(index, btnEl) {
    document.querySelectorAll('.theory-module-btn').forEach(b => b.classList.remove('active'));
    if(btnEl) btnEl.classList.add('active');
    
    const contentBox = document.getElementById('theoryContent');
    contentBox.innerHTML = easaTheoryData[index].content;
    contentBox.scrollTop = 0;
}

function openMission() {
    document.getElementById('menu').style.display = 'none';
    document.getElementById('missionSimulatorScreen').style.display = 'none';
    document.getElementById('missionScreen').style.display = 'flex';
}

function startMission(id) {
    document.getElementById('missionScreen').style.display = 'none';
    document.getElementById('missionSimulatorScreen').style.display = 'flex';
    
    const title = document.getElementById('simStepTitle');
    const desc = document.getElementById('simStepDesc');
    const options = document.getElementById('simOptions');
    
    if(id === 1) {
        title.innerText = "Βήμα 1: Αξιολόγηση Περιβάλλοντος (Επιθεώρηση Κτιρίου)";
        desc.innerText = "Βρίσκεστε σε αστικό περιβάλλον (Α2). Υπάρχει ένα άτομο στα 10 μέτρα. Το drone σας είναι C2 και έχει λειτουργία χαμηλής ταχύτητας. Τι κάνετε;";
        options.innerHTML = `
            <button class="sim-btn" onclick="missionResult(false)">Απογειώνομαι κανονικά, επιτρέπεται μέχρι 5 μέτρα.</button>
            <button class="sim-btn" onclick="missionResult(true)">Ενεργοποιώ το low-speed mode (max 3m/s) και μετά απογειώνομαι.</button>
            <button class="sim-btn" onclick="missionResult(false)">Πλησιάζω το άτομο και του ζητάω να κρατήσει το drone.</button>
        `;
    } else if (id === 2) {
        title.innerText = "Βήμα 1: Νυχτερινή Πτήση (Έρευνα SAR)";
        desc.innerText = "Επιχειρείτε SAR στο βουνό, νύχτα (C3). Ο άνεμος είναι 12m/s. Τι πρέπει να έχετε ενεργοποιημένο οπωσδήποτε στο drone;";
        options.innerHTML = `
            <button class="sim-btn" onclick="missionResult(false)">Τα μπροστινά LED λευκού χρώματος.</button>
            <button class="sim-btn" onclick="missionResult(true)">Ένα πράσινο αναλάμπον (flashing) φως στην κάτω πλευρά.</button>
            <button class="sim-btn" onclick="missionResult(false)">Ηχητικό σήμα (buzzer) συνεχούς λειτουργίας.</button>
        `;
    } else {
        title.innerText = "Βήμα 1: Πτήση πάνω από καλλιέργειες (Ψεκασμός)";
        desc.innerText = "Ψεκάζετε ένα χωράφι. Βλέπετε 2 περαστικούς να μπαίνουν στα όρια του χωραφιού. Τι κάνετε;";
        options.innerHTML = `
            <button class="sim-btn" onclick="missionResult(true)">Διακόπτω άμεσα τον ψεκασμό και απομακρύνω το drone.</button>
            <button class="sim-btn" onclick="missionResult(false)">Χαμηλώνω ύψος και συνεχίζω κανονικά.</button>
            <button class="sim-btn" onclick="missionResult(false)">Τους φωνάζω από μακριά να προσέχουν.</button>
        `;
    }
}

function missionResult(success) {
    const options = document.getElementById('simOptions');
    if(success) {
        options.innerHTML = `<div style="background: rgba(34,197,94,0.2); padding: 20px; border-radius: 8px; border: 1px solid #22c55e;">
            <h3 style="color:#4ade80; margin-top:0;">Αποστολή Επιτυχής!</h3>
            <p>Σωστή απόφαση. Στην υποκατηγορία Α2 (C2), η απόσταση μπορεί να μειωθεί στα 5 μέτρα ΜΟΝΟ εάν είναι ενεργό το low-speed mode.</p>
            <button class="btn-primary" onclick="openMission()" style="margin-top:15px;">Επιστροφή</button>
        </div>`;
    } else {
        options.innerHTML = `<div style="background: rgba(239,68,68,0.2); padding: 20px; border-radius: 8px; border: 1px solid #ef4444;">
            <h3 style="color:#f87171; margin-top:0;">Παραβίαση Ασφαλείας!</h3>
            <p>Λάθος απόφαση. Θέσατε σε κίνδυνο μη εμπλεκόμενο άτομο. Διαβάστε ξανά τους κανόνες αποστάσεων Α2.</p>
            <button class="btn-primary" onclick="openMission()" style="margin-top:15px;">Επιστροφή</button>
        </div>`;
    }
}

function openStudy() {
    document.getElementById('menu').style.display = 'none';
    document.getElementById('studySetup').style.display = 'flex';
}

function openExamConfirm() {
    if(confirm("Προσομοίωση Εξέτασης EASA A2:\n- 40 Ερωτήσεις (Τυχαίες)\n- 60 Λεπτά Χρόνος\n- Βάση Επιτυχίας: 75% (έως 10 λάθη)\n\nΕίστε έτοιμοι;")) {
        startExam();
    }
}

function startStudy() {
    const cat = document.getElementById("studyCategory").value;
    const countVal = document.getElementById("studyCount").value;
    
    let filtered = cat === "Random" ? [...questionsPool] : questionsPool.filter(q => q.cat === cat);
    filtered.sort(() => Math.random() - 0.5);
    
    let limit = countVal === "all" ? filtered.length : parseInt(countVal);
    
    if (filtered.length === 0) {
        alert("Δεν βρέθηκαν ερωτήσεις για αυτή την ενότητα.");
        return;
    }

    selectedQuestions = filtered.slice(0, limit);
    mode = "study";
    examModeActive = false;
    finishModalShown = false;
    document.getElementById("studySetup").style.display = "none";
    initSession("Study Mode: Εξάσκηση", false);
}

function startExam() {
    let pool = [...questionsPool];
    pool.sort(() => Math.random() - 0.5);
    selectedQuestions = pool.slice(0, 40);
    
    mode = "exam";
    examModeActive = true;
    finishModalShown = false;
    document.getElementById("menu").style.display = "none";
    initSession("EASA A2 - Επίσημη Προσομοίωση", true);
}

function initSession(title, isExam) {
    currentQ = 0;
    userAnswers = {};
    flaggedQuestions.clear();
    
    document.getElementById("testScreen").style.display = "flex";
    document.body.style.overflow = "hidden";
    
    document.getElementById("examTypeMock").innerText = title;
    
    const grid = document.getElementById("questionGrid");
    grid.innerHTML = "";
    
    selectedQuestions.forEach((_, idx) => {
        let box = document.createElement("div");
        box.id = "gridBox" + idx;
        box.innerText = idx + 1;
        box.onclick = () => loadQuestion(idx);
        grid.appendChild(box);
    });
    
    const timerEl = document.getElementById("timer");
    timerEl.classList.remove("danger", "warning");
    
    if(isExam) {
        timerEl.style.display = "inline-block";
    } else {
        timerEl.style.display = "none";
    }
    
    startTimer();
    loadQuestion(0);
}

function loadQuestion(idx) {
    currentQ = idx;
    const qData = selectedQuestions[idx];
    
    document.getElementById("qCounter").innerText = `Ερ. ${idx + 1} / ${selectedQuestions.length}`;
    document.getElementById("qCategoryBadge").innerText = qData.cat;
    document.getElementById("questionText").innerText = qData.q;
    
    const expEl = document.getElementById("explanation");
    expEl.style.display = "none";
    expEl.innerHTML = "";

    const pinBtn = document.getElementById("flagBtn");
    if(flaggedQuestions.has(idx)) {
        pinBtn.classList.add("active");
    } else {
        pinBtn.classList.remove("active");
    }

    document.getElementById("noteContainer").style.display = "none";
    const noteArea = document.getElementById("questionNote");
    if(userNotes[qData.q]) {
        noteArea.value = userNotes[qData.q];
        document.getElementById("noteBtn").classList.add("has-note");
    } else {
        noteArea.value = "";
        document.getElementById("noteBtn").classList.remove("has-note");
    }

    for (let i = 0; i < 4; i++) {
        const btn = document.getElementById("btnAns" + i);
        const txt = document.getElementById("ansText" + i);
        
        btn.className = "";
        btn.disabled = false;
        
        if (i < qData.answers.length) {
            btn.style.display = "flex";
            txt.innerText = qData.answers[i];
        } else {
            btn.style.display = "none";
        }
    }
    
    if (userAnswers[idx] !== undefined) {
        updateAnswerUI();
        if(mode === "study") {
            showExplanation(userAnswers[idx] === qData.correct);
            disableAnswers();
        }
    }
    
    updateGrid();
    updateProgress();
}

function answer(idx) {
    if (mode === "study" && userAnswers[currentQ] !== undefined) return;

    userAnswers[currentQ] = idx;
    let isCorrect = (idx === selectedQuestions[currentQ].correct);

    updateAnswerUI();
    
    if (mode === "study") {
        disableAnswers();
        showExplanation(isCorrect);
        if (isCorrect) {
            setTimeout(() => {
                nextQuestion();
            }, 1500);
        }
    } else if (mode === "exam") {
        setTimeout(() => {
            nextQuestion();
        }, 400);
    }
    
    updateGrid();
    updateProgress();
}

function updateAnswerUI() {
    const qData = selectedQuestions[currentQ];
    const ans = userAnswers[currentQ];
    
    for (let i = 0; i < 4; i++) {
        const btn = document.getElementById("btnAns" + i);
        btn.className = "";
        
        if (ans !== undefined) {
            if (mode === "study") {
                if (i === qData.correct) {
                    btn.classList.add("correct");
                } else if (i === ans) {
                    btn.classList.add("wrong");
                }
            } else {
                if (i === ans) {
                    btn.classList.add("selected");
                }
            }
        }
    }
}

function disableAnswers() {
    for (let i = 0; i < 4; i++) {
        document.getElementById("btnAns" + i).disabled = true;
    }
}

function showExplanation(isCorrect) {
    const qData = selectedQuestions[currentQ];
    const expEl = document.getElementById("explanation");
    expEl.style.display = "block";
    
    if(isCorrect) {
        expEl.style.borderLeftColor = "#22c55e";
        expEl.innerHTML = `<span style="color:#16a34a; font-weight:bold;">Σωστό!</span><br><br>${qData.exp}`;
    } else {
        expEl.style.borderLeftColor = "#ef4444";
        const correctLetter = ["A", "B", "C", "D"][qData.correct];
        expEl.innerHTML = `<span style="color:#dc2626; font-weight:bold;">Λάθος. Η σωστή απάντηση είναι η ${correctLetter}.</span><br><br>${qData.exp}`;
    }
}

function flagQuestion() {
    if (flaggedQuestions.has(currentQ)) {
        flaggedQuestions.delete(currentQ);
        document.getElementById("flagBtn").classList.remove("active");
    } else {
        flaggedQuestions.add(currentQ);
        document.getElementById("flagBtn").classList.add("active");
    }
    updateGrid();
}

function toggleNote() {
    const container = document.getElementById("noteContainer");
    container.style.display = container.style.display === "none" ? "block" : "none";
}

function saveNote() {
    const txt = document.getElementById("questionNote").value;
    const qText = selectedQuestions[currentQ].q;
    
    if(txt.trim() === "") {
        delete userNotes[qText];
        document.getElementById("noteBtn").classList.remove("has-note");
    } else {
        userNotes[qText] = txt;
        document.getElementById("noteBtn").classList.add("has-note");
    }
    localStorage.setItem('droneNotes', JSON.stringify(userNotes));
}

function updateGrid() {
    selectedQuestions.forEach((qData, idx) => {
        let box = document.getElementById("gridBox" + idx);
        if(!box) return;
        
        box.className = "";
        
        if (idx === currentQ) box.classList.add("active");
        
        if (flaggedQuestions.has(idx)) box.classList.add("flagged");
        
        if (userAnswers[idx] !== undefined) {
            if (mode === "exam") {
                box.classList.add("answered");
            } else if (mode === "study") {
                if (userAnswers[idx] === qData.correct) {
                    box.classList.add("correct");
                } else {
                    box.classList.add("wrong");
                }
            }
        }
    });
}

function updateProgress() {
    let answeredCount = Object.keys(userAnswers).length;
    let pct = (answeredCount / selectedQuestions.length) * 100;
    document.getElementById("examProgressBar").style.width = pct + "%";

    if (answeredCount === selectedQuestions.length && !finishModalShown) {
        finishModalShown = true;
        setTimeout(() => {
            document.getElementById('autoFinishModal').style.display = 'flex';
        }, 600);
    }
}

function confirmFinish(submit) {
    document.getElementById('autoFinishModal').style.display = 'none';
    if (submit) {
        finishSession();
    }
}

function nextQuestion() {
    if (currentQ < selectedQuestions.length - 1) loadQuestion(currentQ + 1);
}

function prevQuestion() {
    if (currentQ > 0) loadQuestion(currentQ - 1);
}

function startTimer() {
    clearInterval(timerInterval); 
    seconds = mode === "exam" ? examTime : 0; 
    
    const timerEl = document.getElementById("timer");
    
    timerInterval = setInterval(() => {
        if (mode === "exam") {
            seconds--;
            if (seconds <= 0) { finishSession(); return; }
            if (seconds < 300 && seconds > 60) timerEl.classList.add("warning");
            if (seconds <= 60) timerEl.classList.add("danger");
        } else {
            seconds++;
        }
        
        let m = Math.floor(seconds / 60).toString().padStart(2, '0');
        let s = (seconds % 60).toString().padStart(2, '0');
        timerEl.innerText = m + ":" + s;
    }, 1000);
}

function finishSession() {
    clearInterval(timerInterval);
    
    let answered = Object.keys(userAnswers).length;
    if(answered < selectedQuestions.length && mode === "exam") {
        if(!confirm(`Έχετε απαντήσει ${answered} από τις ${selectedQuestions.length} ερωτήσεις. Είστε σίγουροι ότι θέλετε να υποβάλετε;`)) {
            startTimer();
            return;
        }
    }

    document.getElementById("testScreen").style.display = "none";
    document.getElementById("resultScreen").style.display = "flex";
    document.body.style.overflow = "auto";
    
    let correctCount = 0;
    selectedQuestions.forEach((q, i) => {
        if(userAnswers[i] === q.correct) correctCount++;
    });
    
    let score = (correctCount / selectedQuestions.length) * 100;
    
    document.getElementById("finalScore").innerText = Math.round(score) + "%";
    
    const passFail = document.getElementById("passFail");
    if(score >= 75) {
        passFail.innerText = "ΕΠΙΤΥΧΙΑ (PASS)";
        passFail.style.color = "#16a34a";
    } else {
        passFail.innerText = "ΑΠΟΤΥΧΙΑ (FAIL)";
        passFail.style.color = "#dc2626";
    }

    if(mode === "exam") {
        saveExamStats(score);
    } else {
        saveStudyStats();
    }
    
    const timeUsed = mode === "exam" ? examTime - seconds : seconds;
    const m = Math.floor(timeUsed/60);
    const s = timeUsed % 60;
    
    document.getElementById("examStatsSummary").innerHTML = `
        <div class="summary-item"><div class="val">${correctCount}</div><div class="lbl">Σωστές</div></div>
        <div class="summary-item"><div class="val">${selectedQuestions.length - correctCount}</div><div class="lbl">Λάθη / Κενά</div></div>
        <div class="summary-item"><div class="val">${m}m ${s}s</div><div class="lbl">Χρόνος</div></div>
    `;

    generateReviewList();
}

function saveStudyStats() {
    let stats = JSON.parse(localStorage.getItem('studyStats')) || {};
    selectedQuestions.forEach((q, i) => {
        if(userAnswers[i] !== undefined) {
            if(!stats[q.cat]) stats[q.cat] = { total: 0, correct: 0 };
            stats[q.cat].total++;
            if(userAnswers[i] === q.correct) {
                stats[q.cat].correct++;
            }
        }
    });
    localStorage.setItem('studyStats', JSON.stringify(stats));
}

function saveExamStats(score) {
    let history = JSON.parse(localStorage.getItem('examHistory')) || [];
    history.push({
        date: new Date().toLocaleDateString(),
        score: Math.round(score)
    });
    localStorage.setItem('examHistory', JSON.stringify(history));
}

function generateReviewList() {
    const list = document.getElementById("mistakesList");
    list.innerHTML = "";
    
    let mistakes = 0;
    
    selectedQuestions.forEach((q, i) => {
        if (userAnswers[i] !== q.correct) {
            mistakes++;
            let uAnsTxt = userAnswers[i] !== undefined ? q.answers[userAnswers[i]] : "Αναπάντητη";
            let cAnsTxt = q.answers[q.correct];
            
            list.innerHTML += `
                <div style="background: white; border: 1px solid #e2e8f0; border-radius: 8px; padding: 15px; margin-bottom: 15px;">
                    <p style="margin-top:0; font-weight:bold; color:#1e293b;">Ερ ${i+1}. ${q.q}</p>
                    <p style="color:#dc2626; margin: 5px 0;"><strong>Η απάντησή σας:</strong> ${uAnsTxt}</p>
                    <p style="color:#16a34a; margin: 5px 0;"><strong>Σωστή απάντηση:</strong> ${cAnsTxt}</p>
                    <div style="margin-top: 10px; padding: 10px; background: #eff6ff; border-left: 3px solid #3b82f6; font-size: 14px; color: #475569;">
                        ${q.exp}
                    </div>
                </div>
            `;
        }
    });

    if (mistakes === 0) {
        list.innerHTML = "<p style='color:#16a34a; font-weight:bold; font-size:18px; text-align:center;'>Άριστα! Η επίδοσή σας ήταν αλάνθαστη.</p>";
    }
}

function toggleReview() {
    const rev = document.getElementById("reviewSection");
    const btn = document.getElementById("reviewBtn");
    if (rev.style.display === "none") {
        rev.style.display = "block";
        btn.innerText = "Απόκρυψη Λαθών";
    } else {
        rev.style.display = "none";
        btn.innerText = "Εμφάνιση Λαθών";
    }
}

function openStats() {
    document.getElementById('menu').style.display = 'none';
    document.getElementById('studyStatsScreen').style.display = 'none';
    document.getElementById('examStatsScreen').style.display = 'none';
    document.getElementById('statsScreen').style.display = 'flex';
}

function openStudyStats() {
    document.getElementById('statsScreen').style.display = 'none';
    document.getElementById('studyStatsScreen').style.display = 'flex';
    
    const stats = JSON.parse(localStorage.getItem('studyStats')) || {};
    const content = document.getElementById('studyStatsContent');
    content.innerHTML = "";
    
    if(Object.keys(stats).length === 0) {
        content.innerHTML = "<p style='text-align:center; color:#64748b;'>Δεν υπάρχουν δεδομένα μελέτης ακόμη.</p>";
        return;
    }
    
    let html = `
    <table class="stats-table">
        <thead>
            <tr>
                <th>Ενότητα</th>
                <th>Ερωτήσεις</th>
                <th>Σωστές</th>
                <th>Λάθος</th>
                <th>Ποσοστό</th>
            </tr>
        </thead>
        <tbody>
    `;
    
    for(const cat in stats) {
        let total = stats[cat].total;
        let correct = stats[cat].correct;
        let wrong = total - correct;
        let pct = Math.round((correct / total) * 100);
        let color = pct >= 75 ? "#22c55e" : (pct >= 50 ? "#f59e0b" : "#ef4444");
        
        html += `
            <tr>
                <td>${cat}</td>
                <td>${total}</td>
                <td style="color: #22c55e; font-weight: bold;">${correct}</td>
                <td style="color: #ef4444; font-weight: bold;">${wrong}</td>
                <td style="color: ${color}; font-weight: bold;">${pct}%</td>
            </tr>
        `;
    }
    
    html += '</tbody></table>';
    content.innerHTML = html;
}

function openExamStats() {
    document.getElementById('statsScreen').style.display = 'none';
    document.getElementById('resultScreen').style.display = 'none';
    document.getElementById('examStatsScreen').style.display = 'flex';
    
    const history = JSON.parse(localStorage.getItem('examHistory')) || [];
    
    if(history.length === 0) {
        document.getElementById('examOverview').innerHTML = "<p style='text-align:center; color:#64748b; width:100%;'>Δεν υπάρχουν καταγεγραμμένες εξετάσεις.</p>";
        return;
    }
    
    const labels = history.map((_, i) => "Εξ. " + (i+1));
    const data = history.map(h => h.score);
    
    const ctx = document.getElementById('examChart').getContext('2d');
    
    if(window.examChartInstance) {
        window.examChartInstance.destroy();
    }
    
    window.examChartInstance = new Chart(ctx, {
        type: 'line',
        data: {
            labels: labels,
            datasets: [{
                label: 'Βαθμολογία (%)',
                data: data,
                borderColor: '#3b82f6',
                backgroundColor: 'rgba(59, 130, 246, 0.1)',
                borderWidth: 3,
                fill: true,
                tension: 0.3
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            scales: {
                y: {
                    beginAtZero: true,
                    max: 100,
                    grid: { color: 'rgba(0,0,0,0.05)' }
                },
                x: {
                    grid: { display: false }
                }
            },
            plugins: {
                legend: { display: false }
            }
        }
    });
}

function updateGlobalStats() {
}

